var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>그라운드 원 시민 여러분께 안내 말씀드립니다.</color>","JPN":"<color=#ffd34c>グラウンド・ワンの市民の皆さんにご案内します。</color>","ENG":"<color=#ffd34c>Attention all Ground One citizens.</color>","TWN":"<color=#ffd34c>通知G1的市民。</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>현재, 연쇄적 현실 붕괴 현상의 진행이 둔화되면서 대균열에 출몰한 괴생명체가 물러나기 시작했습니다.</color>","JPN":"<color=#ffd34c>ただいま、連鎖的な現実崩壊現象の進行が鈍化し、大亀裂に出没した怪生命体が退却しはじめました。</color>","ENG":"<color=#ffd34c>The chain of reality collapses have started to slow down, and the mysterious creature that appeared in the Grand Dimension Crevice has begun to retreat.</color>","TWN":"<color=#ffd34c>目前連鎖現實崩壞現象已經趨緩下來，在大峽谷出沒的怪物開始撤退。</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>각 태스크포스는 전투 태세를 유지한 상태로 지시를 기다려 주시기 바랍니다.</color>","JPN":"<color=#ffd34c>各タスクフォースは戦闘態勢を維持したまま、指示をお待ちください。</color>","ENG":"<color=#ffd34c>To all TASKFORCEs, please maintain battle positions until further notice.</color>","TWN":"<color=#ffd34c>請各個特遣勢力維持戰鬥狀態，等候進一步指示。</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>반복합니다. 현재, 연쇄적 현실 붕괴 현상의 진행이 둔화되었으며……</color>","JPN":"<color=#ffd34c>繰り返します。ただいま、連鎖的な現実崩壊現象の進行が鈍化し……</color>","ENG":"<color=#ffd34c>I repeat, the chain of reality collapses have started to slow down...</color>","TWN":"<color=#ffd34c>再重複一次。目前連鎖現實崩壞現象已經趨緩下來……</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"오셨습니까, 단장님.","JPN":"お帰りなさい、団長。","ENG":"You're here, Captain.","TWN":"你來了，團長。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"기사단은 전원 전투 태세로 대기 중입니다.","JPN":"騎士団は全員戦闘態勢で待機しております。","ENG":"The order is on standby, ready to fight.","TWN":"騎士團全員已經進入作戰狀態。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"수고했다, 부단장. 지휘는 내가 맡을 테니 잠시 쉬도록.","JPN":"ご苦労だった、副団長。指揮は私が執ろう。君はしばらく休め。","ENG":"Good work, Deputy. I'll take the lead from now, go and get some rest.","TWN":"辛苦了，副團長。我來指揮，你休息一會兒。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"아닙니다. 단장님께서도 회의장 경호 지원으로 고생하셨을 테니까요.","JPN":"いいえ。団長も会議場の警護の支援でお疲れでしょうから。","ENG":"No. You must have had a long day yourself, from supporting the conference room security.","TWN":"沒關係，團長支援會場的警戒工作也很辛苦。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"그런데 오늘은 평소와 다르군요. 대균열에 이변이 생겼는데도 회의를 속행하다니.","JPN":"しかし、今日はいつもとは違いましたね。大亀裂の異変が起きている最中にも関わらず、会議を続行するなんて。","ENG":"Today is quite different from the usual ones, though. They're proceeding with the meeting, even with disturbance in the Grand Dimension Crevice.","TWN":"不過大峽谷發生了這樣的異變，居然還在繼續開會，似乎和以前有些不太一樣？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"관리국에서 언질은 없었습니까?","JPN":"管理局から何か言われませんでしたか？","ENG":"Any news from the Administration?","TWN":"管理局沒說什麼嗎？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"오늘 중으로 회의가 끝날지도 미지수야. 관계자들도 당황한 기색이더군.","JPN":"今日中に会議が終わるかどうかもわからない。関係者たちも焦っている様子だった。","ENG":"I'm not even sure if the meeting is going to end today. The authorities looked pretty confused as well.","TWN":"今天之內會議能否結束還是個未知數。當局的態度看起來似乎也很不明確。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"관리국 직할 도시를 담당하는 최고 관리자들이 모두 출석했다고 들었습니다만…….","JPN":"管理局直轄都市を司る最高管理者たちが揃って出席したと聞いたのですが……","ENG":"I heard that every Supreme Administrator in charge of the Administration Direct Control Cities attended...","TWN":"聽說負責管理局直轄市的最高管理階層全都出席了……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"오늘 안건은 상당히 중요한 사안인가 보군요.","JPN":"今日の案件はそれほど重要なものなんですね。","ENG":"Today's meeting must have been about something important indeed.","TWN":"看來今天的會議相當重要……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"……그렇겠지. 아마도.","JPN":"……ああ。おそらくな。","ENG":"...Yes. Perhaps.","TWN":"……大概，是吧。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"안색이 좋지 않아 보입니다, 단장님.","JPN":"顔色が良くありませんね、団長。","ENG":"You don't look very well, Captain.","TWN":"你的臉色不太好，團長。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"그런가? 다른 단원들 앞에서는 주의해야겠군.","JPN":"そうか？　他の団員の前では注意しないとな。","ENG":"Is that so? I should be careful in front of the other members.","TWN":"是嗎？在其他團員面前要小心了呢。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"버밍엄 교수님에 대한 소식은 저도 주교님께 전해 들었습니다.","JPN":"バーミンガム教授の件は、私も司教から聞きました。","ENG":"I heard the news from the bishop, regarding Professor Birmingham.","TWN":"伯明罕教授的消息我也聽主教說了。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"그래. 마지막으로 편지가 왔던 그 날 이후로 행방이 묘연해지셨더군.","JPN":"ああ。最後の手紙が届いて以来、消息を絶たれたらしい。","ENG":"Yes. He has gone missing since the last letter arrived.","TWN":"嗯，收到信的那天之後就下落不明了。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"학생들에게 위해를 가했다는 시점과 시기상으로도 일치해.","JPN":"学生たちに危害を加えたのと、時期が一致している。","ENG":"It matches the date when he harmed his students.","TWN":"從學生遇險的時間點來看也對得上。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"구조 요청 무전들에서 묘사된 적들의 무장은 저희 기사단과 매우 흡사합니다.","JPN":"救助要請の無線で描写されていた敵の武装は、我々騎士団のものと酷似しています。","ENG":"The appearance of the enemies described in the rescue request radio resembles our knights.","TWN":"求救無線電中所描述的敵人武裝和我們騎士團非常相似。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"단정짓기에는 이르지만, 평기사 분들의 우려가 기우로 그치지만은 않을 것 같군요.","JPN":"まだ断定はできませんが、平騎士たちの心配が杞憂では終わらないと思います。","ENG":"It is too early to presume things, but I fear that the knight bachelors' worries might end up being true.","TWN":"現在下斷言還為時尚早，但平民騎士們的擔心似乎也不是杞人憂天。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"단장님께서는 평소에 그 분께 조언을 구하러 종종 교류하셨죠.","JPN":"団長は普段からあの方に助言をもらったり、交流がありましたよね。","ENG":"I know you talked with him every now and then for advice, Captain.","TWN":"團長你平時經常和他交流，聽取他的建議。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"그렇기에 학생들의 증언을 받아들이기 어렵다는 점도 잘 압니다.","JPN":"だからこそ、学生たちの証言が受け入れがたいのはわかります。","ENG":"I know you find it hard to accept the testimonies from the students.","TWN":"所以我知道你很難接受學生的證詞。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"버밍엄 가문은 기사단의 오랜 조력자였지만……","JPN":"バーミンガム家は騎士団と長く協力関係にありましたが……","ENG":"The Birmingham family has assisted the knights for a long time...","TWN":"伯明罕家族一直以來都是騎士團的幫手……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"대외 활동에는 대대로 소극적이었죠.","JPN":"対外的な活動には代々消極的な態度でした。","ENG":"But they were very timid when it came to social activities.","TWN":"但在對外活動中，每一代都很消極。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"버밍엄 교수님도 마찬가지입니다.","JPN":"バーミンガム教授も同じです。","ENG":"It was the same for Professor Birmingham.","TWN":"伯明罕教授也一樣。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"기사단의 눈이 닿지 않는 곳에서 무슨 행적을 벌였을지, 저희로서는 알 수 없습니다.","JPN":"騎士団には気づかれないところで何をしていたかは、私たちにはわかりません。","ENG":"We don't know what he might have done outside of the knights' watch.","TWN":"在騎士團看不到的地方他都做了什麼事，我們也無從知曉。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"……알고 있다.","JPN":"……ああ、知っている。","ENG":"...I know that.","TWN":"……我知道。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"오늘은 평소보다 검이 무겁더군.","JPN":"今日は普段より剣に迷いがあった。","ENG":"Your sword was more sluggish than usual.","TWN":"你今天的動作比較沒那麼俐落喔。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"고민거리가 있다면 얘기해 보게.","JPN":"悩みがあるなら言ってみたまえ。","ENG":"You can talk to me if something is troubling you.","TWN":"有什麼煩惱的話可以說出來。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"상담도 전술학의 일부란 사실은 처음 알았습니다.","JPN":"相談も戦術学の一部だとは知りませんでした。","ENG":"I didn't know consultation was part of strategy class.","TWN":"原來心理諮商也是戰術學的一部份嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"학생들의 고충을 상담해 주는 건 교사가 당연히 해야 할 일이라네.","JPN":"学生の悩みを聞くのは教師として当然のことだ。","ENG":"It is my duty as a mentor to help my students with their issues.","TWN":"聆聽學生的煩惱是老師應該做的吧。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"하지만 교육자로서는 좋은 사람이었어. 그것만은 단언할 수 있다.","JPN":"しかし、良き教育者ではあった。それだけは断言できる。","ENG":"But he was a good teacher. That, I can guarantee.","TWN":"但他是個優秀的教育者，這一點我可以肯定。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"자기 이득 때문에 학생들을 위험에 빠뜨릴 사람은 아니었어.","JPN":"己の利益のために学生を危ない目に遭わせるような人物ではなかった。","ENG":"He was not one to put his students in danger for his own profit.","TWN":"他不是會因為自己的利益而讓學生陷入危險的人。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"지금은……. 무언가 오해가 있었을 거라고 믿고 싶군.","JPN":"今は……何か誤解があるのだと、そう信じたい。","ENG":"For now... I wish for this to be a misunderstanding.","TWN":"現在……我寧願相信這其中是有什麼誤會。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"……이건, 경고음?","JPN":"……これは、警報？","ENG":"...That's the warning alarm.","TWN":"……這是，警報？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L1_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"함교, 무슨 일이지?","JPN":"艦橋、何が起きている？","ENG":"Bridge, do you copy? What's going on?","TWN":"艦橋，發生什麼事了？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"미안, 부단장! 깜짝 놀랐지?","JPN":"ごめん、副団長！　びっくりした？","ENG":"Sorry, Deputy! I didn't mean to startle you.","TWN":"對不起，副團長！我不是有意嚇你的！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L4_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"방금 관리국에서 연락이 왔는데, 감시 장비에 오류가 있었다나 봐.","JPN":"さっき管理局から連絡があったんだけど、監視装備にトラブルがあったんだって。","ENG":"The Administration just called, there was some kind of an error with the surveillance device.","TWN":"剛才管理局聯繫我們，好像說是監控設備發生故障。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"감시 장비에 말입니까?","JPN":"監視装備にですか？","ENG":"The surveillance device?","TWN":"監控設備？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"조금 더 자세히 설명해 줄 수 있겠나?","JPN":"もう少し詳しく説明してくれるか？","ENG":"Would you care to elaborate?","TWN":"你能說得更詳細一點嗎？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"어, 음, 그러니까 뭐라더라~","JPN":"あ、うん、えーっと、何だっけな～","ENG":"Um, so what they said was...","TWN":"喔，嗯，他們是怎麼說的呢～"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"YANGHANSOL_ZODIAC_NULL_NULL","text":{"KOREA":"저심도 이면세계에 긴급 배치된 감시 위성들이 동시에 급격한 온도 상승을 감지했습니다.","JPN":"低深度裏世界に緊急配置された各監視衛星が、一斉に急激な温度の上昇を感知しました。","ENG":"The surveillance satellites dispatched in the shallow dives of the Counterside sensed an abrupt rise in temperature simultaneously.","TWN":"感應到在低深度異界緊急部署的監視衛星溫度同時急遽上升。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L14_1","type":"dialog","speaker":"YANGHANSOL_ZODIAC_NULL_NULL","text":{"KOREA":"좌표가 전부 제각각인 데다가, 상승폭도 계측치를 초과해서 오류로 판단했다고 합니다.","JPN":"座標もすべてバラバラで、上昇幅も計測値の限度を超えていたので、不具合として判断したそうです。","ENG":"The coordinates were all over the place, and the rise was too drastic for the machines to calculate. Hence the error.","TWN":"由於座標分佈太廣，上升幅度也超出可測量值，所以判定是故障。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"YANGHANSOL_ZODIAC_NULL_NULL","text":{"KOREA":"이상! 보고 끝!","JPN":"報告は以上です！","ENG":"End of report, over!","TWN":"以上，報告完畢！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L16_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"오오! 한솔 군, 땡큐 땡큐!","JPN":"おお！　ヤガミくん、感謝感謝！","ENG":"Ooh! Many thanks, Hansol!","TWN":"喔喔，楊瀚，謝謝你！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L18_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"알겠다. 아직 상황이 완전히 끝난 것은 아니니, 긴장을 잃지 말도록.","JPN":"了解した。まだ状況が完全に終息したわけではないから、気を抜かないように。","ENG":"I see. The situation isn't completely over yet. Don't lower your guard.","TWN":"知道了。狀況還沒有徹底結束，不要鬆懈。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"오늘은 처음부터 끝까지 수상한 일뿐이군요.","JPN":"今日は何から何まで、怪しいことばかりが起きていますね。","ENG":"Today was full of strange happenings.","TWN":"今天從頭到尾都是奇怪的一天啊。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"괴생명체 때문일까요? 아니면 이면세계에 나타났다는 그 기사들?","JPN":"あの化け物のせいでしょうか？　それとも裏世界に現れたという騎士たちのせい？","ENG":"Perhaps it's because of the monster? Or the knights that appeared in the Counterside?","TWN":"會是因為那個怪物嗎？還是因為出現在異界的那些騎士？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"확신하기에는 일러.","JPN":"まだ確信はできない。","ENG":"We can't be sure yet.","TWN":"現在確定還早了點。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"하지만 기계의 오류라기에는…… 시기가 지나치게 절묘하군.","JPN":"しかし機械トラブルと片付けるには……タイミングがあまりにも絶妙すぎる。","ENG":"But to consider it a technical error... is too much of a coincidence.","TWN":"不過說是機器故障……時機有點過於微妙了。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"경계를 철저히 하도록. 조만간 사건이 있을지도 모르겠어.","JPN":"警戒を怠らないように。近いうちに事件が起きるかもしれない。","ENG":"Strengthen the security. I have a feeling something is going to happen soon.","TWN":"全面戒備，恐怕事有蹊蹺。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"}]`);export{e as default};